/* ---------- stateless text-node translator ---------- */
(function () {
  var KEY = "bild-lang";
  var LANGS = ["EN", "FI", "SV"];
  var saved = null;
  try { saved = localStorage.getItem(KEY); } catch (e) {}
  var lang = LANGS.indexOf(saved) >= 0 ? saved : "EN";

  function translate(l) {
    lang = l;
    try { localStorage.setItem(KEY, l); } catch (e) {}
    document.documentElement.lang = l === "FI" ? "fi" : l === "SV" ? "sv" : "en";
    var dict = I18N[l] || {};

    var walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT, null);
    var n;
    while ((n = walker.nextNode())) {
      var p = n.parentNode;
      if (!p || p.nodeName === "SCRIPT" || p.nodeName === "STYLE") continue;
      if (n.__en === undefined) n.__en = n.nodeValue;
      var raw = n.__en;
      var key = raw.trim();
      if (!key) continue;
      var tr = dict[key];
      n.nodeValue = tr ? raw.replace(key, tr) : raw;
    }

    document.querySelectorAll("[placeholder]").forEach(function (el) {
      if (el.__enPh === undefined) el.__enPh = el.getAttribute("placeholder");
      el.setAttribute("placeholder", dict[el.__enPh] || el.__enPh);
    });

    document.querySelectorAll(".lang-switch button").forEach(function (b) {
      var on = b.dataset.lang === l;
      b.classList.toggle("on", on);
      if (on) b.setAttribute("aria-pressed", "true");
      else b.setAttribute("aria-pressed", "false");
    });

    document.querySelectorAll(".lang-select").forEach(function (sel) {
      sel.value = l;
    });
  }

  window.BILD_setLang = translate;
  window.BILD_getLang = function () { return lang; };

  document.addEventListener("DOMContentLoaded", function () {
    document.querySelectorAll(".lang-switch button").forEach(function (b) {
      b.addEventListener("click", function () { translate(b.dataset.lang); });
    });
    document.querySelectorAll(".lang-select").forEach(function (sel) {
      sel.addEventListener("change", function () { translate(sel.value); });
    });
    translate(lang);
  });
})();
